   221→      handleCloseInfo={handleCloseInfo}
   222→      isLoading={isLoading}
   223→      hasError={hasError}
   224→      handleRetry={handleRetry}
   225→      isCashback={isCashback}
   226→      cardTitle={processedData.cardTitle}
